INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00379', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '依據學者GossandUyesugi（1995）的研究，施行動態視網膜檢影鏡鏡檢法（retinoscopy）檢查年輕近視被 檢者時，發現有大於標準值的調節滯後度數時（如+1.25DS），則最佳的處置方式為以下何者？', '["額外處方近距離閱讀的正球面度數眼鏡", "額外處方近距離閱讀的負球面度數眼鏡", "額外處方近距離閱讀的稜鏡基底朝外（baseout）眼鏡", "不必特別處置"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00380', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '剛開始利用綜合驗光儀（phoropter）與視網膜檢影鏡鏡檢法（retinoscopy）平行光檢查被檢者時，水平掃動 時為順動現象，垂直掃動時為逆動現象，下列敘述何者正確？', '["應先中和垂直軸，此眼屈光不正為逆散現象", "應先中和垂直軸，此眼屈光不正為順散現象", "應先中和水平軸，此眼屈光不正為逆散現象", "應先中和水平軸，此眼屈光不正為順散現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00381', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於視力量測，下列敘述何者正確？', '["史耐倫（Snellen）視力檢查表視標的字母或數字大小順序、字型與數量等都有嚴格標準", "當使用的視力表最小值為20/20，而受測者也確實讀出了，代表受測者的「閾值」視力為1.0", "臨床研究上最可靠，最有辨別度的是logMAR視力檢查表，而非Snellen視力檢查表", "對於視力極差的患者，使用Snellen視力檢查表與使用logMAR視力檢查表的效果相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00382', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '視網膜檢影鏡檢查，當受檢者只有球面度數，如果是順動時，每次應該加入那一種鏡片直到中和為止？', '["散光+0.25DC", "散光-0.25DC", "球面+0.25DS", "球面-0.25DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00383', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '臨床上各種不同型態的散光中，下列何者可以透過驅動調節力將最小模糊圓（circleofleastconfusion）移 至視網膜，使視力獲得改善？', '["混合性散光", "單純性近視散光", "複合性近視散光", "複合性遠視散光"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00384', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '檢影結束後，得知患者右眼的處方為-3.00DS/-2.00DC 180，若此時使用傑克森交叉圓柱鏡（Jackson’scross- cylinderlenstest）做散光度數檢查，當散光度數修正為-2.50DC時，此時球面度數應修正為下列何者？', '["-2.75DS", "-3.25DS", "-×2.50DS", "-3.50DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00385', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '若患者的角膜弧度儀（Keratometry）量測值為：OD：43.25@005/44.50@115；OS：42.50@180/44.25@085， 且雙眼VA皆為0.8，下列何種散光檢查的方式較適合幫助此患者確認其散光度數及最佳矯正視力（MPMVA）？', '["鐘面圖（clockdialtest）", "傑克森交叉圓柱鏡（Jackson’scross-cylinderlenstest）", "裂孔板（StenopaicSilt）", "扇形圖（FanChart）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00386', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於散光自覺式驗光何者正確？', '["使用鐘面圖（clockdialtest）3和9點鐘方向水平的影像最清楚，受測者的散光軸約為180度", "使用鐘面圖前，先霧視的目的是使最小模糊圈前移聚焦在視網膜前方", "使用傑克森交叉圓柱鏡（Jackson’scross-cylinderlenstest）前，需要先霧視目的是使最小模糊圈前移聚焦 在視網膜前方", "鐘面圖能比傑克森交叉圓柱鏡（Jackson’scross-cylinderlenstest）測得散光軸度及精準的散光度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00387', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於雙眼自覺式驗光（binocularsubjectiverefraction）的敘述，下列何者錯誤？', '["雙眼自覺式驗光的檢查不適合優勢眼（dominanteye）與非優勢眼（non-dominanteye）反應相差很大的 患者", "雙眼自覺式驗光於假性近視（pseudomyopia）及遠視（hyperopia）受測者，有助測得更精確的矯正度數", "此種方式較單眼自覺式驗光能控制及放鬆較多的調節", "單眼自覺式驗光（monocularsubjectiverefraction）完成後進行雙眼平衡檢測（binocularbalance），與雙眼 自覺式驗光（binocularsubjectiverefraction）相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00388', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用散光圖形檢查法確認散光的粗略數軸度（粗軸），患者回報1點鐘方向最黑，12點至1點間的線條比 1點到2點間的線條較黑。若要用正性散光來矯正，你應該將鏡片的軸度放在那個方向較為適當？', '["010度", "020度", "100度", "110度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
